#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        char B[6];
        scanf("%d %s", &N, B);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        int found = 0;
        for (int i0 = 0; i0 < N; i0++) {
            for (int i1 = i0 + 1; i1 < N; i1++) {
                for (int i2 = i1 + 1; i2 < N; i2++) {
                    for (int i3 = i2 + 1; i3 < N; i3++) {
                        for (int i4 = i3 + 1; i4 < N; i4++) {
                            int sub[5] = {A[i0], A[i1], A[i2], A[i3], A[i4]};
                            int sorted[5];
                            memcpy(sorted, sub, sizeof(int) * 5);
                            qsort(sorted, 5, sizeof(int), compare);
                            int ranks[5];
                            for (int i = 0; i < 5; i++) {
                                for (int j = 0; j < 5; j++) {
                                    if (sub[i] == sorted[j]) {
                                        ranks[i] = j + 1;
                                    }
                                }
                            }
                            char rankStr[6];
                            sprintf(rankStr, "%d%d%d%d%d", ranks[0], ranks[1], ranks[2], ranks[3], ranks[4]);
                            if (strcmp(rankStr, B) == 0) {
                                printf("%d %d %d %d %d\n", i0, i1, i2, i3, i4);
                                found = 1;
                                break;
                            }
                        }
                        if (found) break;
                    }
                    if (found) break;
                }
                if (found) break;
            }
            if (found) break;
        }
        if (!found) printf("-1\n");
    }
    return 0;
}

